import React from 'react';
import { Col, Offcanvas, Button, Form } from 'react-bootstrap';
import CompanyFilter from './CompanyFilter';
import './FilterPanel.css';

export default function FilterPanel({
  companies,
  selectedCompanies,
  toggleCompany,
  divisionFilter,
  setDivisionFilter,
  filterOpen,
  setFilterOpen
}) {
  const renderBody = () => (
    <>
      <div><strong>Company</strong></div>
      <CompanyFilter
        companies={companies}
        selected={selectedCompanies}
        onToggle={toggleCompany}
      />
      <hr />
      <div className="division-filter">
        <div><strong>Division</strong></div>
        {['All', "Men's", "Women's"].map(div => (
          <Form.Check
            key={div}
            type="radio"
            id={`div-${div.toLowerCase().replace("'", '')}`}
            label={div === 'All' ? 'All' : `${div}`}
            name={`division-${div}`}
            checked={divisionFilter === div}
            onChange={() => setDivisionFilter(div)}
          />
        ))}
      </div>
    </>
  );

  return (
    <>
      {/* Desktop sidebar */}
      <Col
        xs={12}
        md={3}
        lg={2}
        className="bg-light border-end d-none d-md-block sidebar"
      >
        {renderBody()}
      </Col>

      {/* Mobile Offcanvas */}
      <Offcanvas
        show={filterOpen}
        onHide={() => setFilterOpen(false)}
        className="d-md-none"
        placement="start"
      >
        <Offcanvas.Header closeButton>
          <Offcanvas.Title>Filters</Offcanvas.Title>
        </Offcanvas.Header>
        <Offcanvas.Body>
          {renderBody()}
        </Offcanvas.Body>
      </Offcanvas>

      {/* Mobile filter toggle */}
      <Button
        variant="outline-secondary"
        className="d-md-none mb-3 hamburger"
        onClick={() => setFilterOpen(true)}
      >
        ☰ Filter
      </Button>
    </>
  );
}
